import{_ as e,o as a,c as d,a2 as i}from"./chunks/framework.CZqXuAiL.js";const f=JSON.parse('{"title":"L2/L3/L4 Detection","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/detection-engine/l3-l4.md","filePath":"openshield-xdp/detection-engine/l3-l4.md","lastUpdated":null}'),o={name:"openshield-xdp/detection-engine/l3-l4.md"};function s(r,t,l,n,h,c){return a(),d("div",null,[...t[0]||(t[0]=[i(`<h1 id="l2-l3-l4-detection" tabindex="-1">L2/L3/L4 Detection <a class="header-anchor" href="#l2-l3-l4-detection" aria-label="Permalink to &quot;L2/L3/L4 Detection&quot;">​</a></h1><p>Validation checks that run before rate tracking. These drop packets that shouldn&#39;t exist on a properly configured network.</p><h2 id="l2-—-mac-filter" tabindex="-1">L2 — MAC filter <a class="header-anchor" href="#l2-—-mac-filter" aria-label="Permalink to &quot;L2 — MAC filter&quot;">​</a></h2><p>Evaluated before any IP parsing. Two modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behaviour</th><th>Config</th></tr></thead><tbody><tr><td>Blacklist</td><td>Drop frames matching configured MACs</td><td><code>mac_filter_mode: 2</code></td></tr><tr><td>Whitelist</td><td>Drop frames NOT matching configured MACs</td><td><code>mac_filter_mode: 1</code></td></tr><tr><td>Disabled</td><td>Pass all frames</td><td><code>mac_filter_mode: 0</code></td></tr></tbody></table><p>Up to 8 MAC addresses. Pre-loaded into a 8×6 byte array in the config struct. Zero entries → fast-path skip.</p><div class="warning custom-block"><p class="custom-block-title">MAC filter runs first</p><p>A MAC filter rejection happens before <code>parse_packet()</code> — no IP header parsing overhead for L2-rejected frames.</p></div><h2 id="l3-—-ip-validation" tabindex="-1">L3 — IP validation <a class="header-anchor" href="#l3-—-ip-validation" aria-label="Permalink to &quot;L3 — IP validation&quot;">​</a></h2><h3 id="ipv4-private-bogon-ranges" tabindex="-1">IPv4 private/bogon ranges <a class="header-anchor" href="#ipv4-private-bogon-ranges" aria-label="Permalink to &quot;IPv4 private/bogon ranges&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Range</th><th>Description</th></tr></thead><tbody><tr><td><code>10.0.0.0/8</code></td><td>Private (RFC 1918)</td></tr><tr><td><code>172.16.0.0/12</code></td><td>Private (RFC 1918)</td></tr><tr><td><code>192.168.0.0/16</code></td><td>Private (RFC 1918)</td></tr><tr><td><code>127.0.0.0/8</code></td><td>Loopback</td></tr><tr><td><code>169.254.0.0/16</code></td><td>Link-local</td></tr><tr><td><code>0.0.0.0/8</code></td><td>Reserved</td></tr><tr><td><code>224.0.0.0/4</code></td><td>Multicast (cannot be source)</td></tr></tbody></table><h3 id="ipv6-private-bogon-ranges" tabindex="-1">IPv6 private/bogon ranges <a class="header-anchor" href="#ipv6-private-bogon-ranges" aria-label="Permalink to &quot;IPv6 private/bogon ranges&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Range</th><th>Description</th></tr></thead><tbody><tr><td><code>::1/128</code></td><td>Loopback</td></tr><tr><td><code>::/128</code></td><td>Unspecified</td></tr><tr><td><code>fe80::/10</code></td><td>Link-local</td></tr><tr><td><code>fc00::/7</code></td><td>Unique local</td></tr><tr><td><code>ff00::/8</code></td><td>Multicast (cannot be source)</td></tr><tr><td><code>::ffff:0:0/96</code></td><td>IPv4-mapped</td></tr></tbody></table><h3 id="malformed-l3" tabindex="-1">Malformed L3 <a class="header-anchor" href="#malformed-l3" aria-label="Permalink to &quot;Malformed L3&quot;">​</a></h3><ul><li>IP version check (IPv4 ≠ 4, IPv6 ≠ 6)</li><li>IHL &lt; 5 (IPv4)</li><li>IP header extends past <code>data_end</code></li><li><code>total_len</code> &lt; header length</li><li>IPv6 extension header overflow (&gt; 4 headers)</li></ul><h2 id="l4-—-tcp-udp-icmp" tabindex="-1">L4 — TCP/UDP/ICMP <a class="header-anchor" href="#l4-—-tcp-udp-icmp" aria-label="Permalink to &quot;L4 — TCP/UDP/ICMP&quot;">​</a></h2><h3 id="bogus-tcp-flags" tabindex="-1">Bogus TCP flags <a class="header-anchor" href="#bogus-tcp-flags" aria-label="Permalink to &quot;Bogus TCP flags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Drops</th><th>Reason</th></tr></thead><tbody><tr><td>SYN + FIN</td><td>Impossible combination</td></tr><tr><td>SYN + RST</td><td>Impossible combination</td></tr><tr><td>FIN + RST</td><td>Impossible combination</td></tr><tr><td>All 8 flags set</td><td>TCP flag stuffing</td></tr><tr><td>No flags set</td><td>NULL scan</td></tr></tbody></table><p>::: note RFC 3168 compliance ECE and CWR flags are explicitly allowed. Packets with ECN are not dropped. :::</p><h3 id="tcp-doff-validation" tabindex="-1">TCP doff validation <a class="header-anchor" href="#tcp-doff-validation" aria-label="Permalink to &quot;TCP doff validation&quot;">​</a></h3><p><code>tcp-&gt;doff</code> must be ≥ 5 before any payload offset calculation. Prevents underflow in <code>l4_payload_len</code> computation.</p><h3 id="malformed-l4-bounds" tabindex="-1">Malformed L4 bounds <a class="header-anchor" href="#malformed-l4-bounds" aria-label="Permalink to &quot;Malformed L4 bounds&quot;">​</a></h3><p>Each L4 header type is bounds-checked independently: TCP, UDP, ICMP, ICMPv6. <code>pkt_len</code> is <code>u32</code> to prevent overflow on high-bandwidth links.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">validation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  filter_private</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Drop private/bogon source IPs</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  filter_bogon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Drop bogon source IPs</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  filter_bogus_tcp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Drop impossible TCP flag combos</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  filter_malformed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Drop malformed headers</span></span></code></pre></div><h2 id="related-pages" tabindex="-1">Related pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related pages&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/detection-engine/rate-based">Rate-Based Detection</a> · <a href="/pingless-studios-docs/openshield-xdp/detection-engine/pipeline">Pipeline</a></p>`,26)])])}const b=e(o,[["render",s]]);export{f as __pageData,b as default};
